var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"SCN No. TPM001M000139-05\\n<color=#ffd34c>3급 요인</color> 열람 승인 자료\\n부록: 인물 과거 조사","JPN":"SCN No. TPM001M000139-05\\n<color=#ffd34c>3級要人</color>閲覧承認資料\\n付録：人物の過去調査","ENG":"[[","TWN":"SCN No.TPM001M000139-05\\n<color=#ffd34c>3級要員</color> 閱覽審批資料\\n附錄人物過往調查","THA":"SCN หมายเลข TPM001M000139-05\\n<color=#ffd34c>ระดับปล่อยผ่าน 3</color> ข้อมูลลับ\\nภาคผนวก: ผลการตรวจสอบประวัติส่วนบุคคล","VTN":"SCN Số TPM001M000139-05\\n<color=#ffd34c>Cấp Độ An Ninh III</color> Thông Tin Tối Mật\\nPhụ lục: Kết Quả Thẩm Vấn Bối Cảnh Cá Nhân","SCN":"SCN No.TPM001M000139-05\\n<color=#ffd34c>3级要人</color> 阅览审批资料\\n附录人物过往调查","DEU":"SCN-Nr. TPM001M000139-05\\n<color=#ffd34c>Freigabestufe\xA0III</color> Verschlusssache\\nAnhang: Ergebnisse der Untersuchung des persönlichen Hintergrunds","FRA":"SCN No. TPM001M000139-05\\n<color=#ffd34c>Sécurité niveau III</color> Information confidentielle\\nAnnexe\xA0: Résultats de l'enquête de moralité"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"DIRECTOR_NPC_NULL_NULL","text":{"KOREA":"좋아! 오늘 컨디션 나쁘지 않은데? 또 기록을 갱신했다고!","JPN":"よし！　今日も調子がいいな！　また記録を更新したぞ！","ENG":"Great! You must be in tiptop shape today! You just broke the record again!","TWN":"漂亮！今天狀態不錯啊？又刷新了記錄！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DIRECTOR_NPC_NULL_NULL","text":{"KOREA":"신예치곤 굉장하구만. 이 정도면 시즌우승컵도 노려 볼만 하겠는데?","JPN":"新人なのにすごいな。この調子なら、シーズンの優勝も狙えそうだ。","ENG":"That's pretty impressive for someone new. At this rate, we could even aim for the season championship.","TWN":"以新人來說真是了不起，這種程度的話，應該有拿下季賽冠軍的潛力吧？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DRIVER_NPC_NULL_NULL","text":{"KOREA":"감사합니다, 감독님!","JPN":"ありがとうございます、監督！","ENG":"Thanks, Director!","TWN":"謝謝你，教練！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SENIOR_NPC_NULL_NULL","text":{"KOREA":"너무 추켜세워주지 마시죠, 선수 버릇 나빠집니다.","JPN":"調子に乗ると困るので、ほどほどにしてください。","ENG":"Go easy on the praise, Director. You'll spoil him.","TWN":"不要太吹捧他啦，選手養出壞習慣來的。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DIRECTOR_NPC_NULL_NULL","text":{"KOREA":"하하, 이 사람아. 칭찬 아껴뒀다 뭐에 쓰게?","JPN":"はは、そう言うな。俺は褒めて伸ばすタイプなんだ。","ENG":"Aw, come on. You've got to give praise where praise is due.","TWN":"哈哈，你這個人。這麼捨不得誇獎別人，是會少塊肉嗎？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DIRECTOR_NPC_NULL_NULL","text":{"KOREA":"이 기세라면 코스레코드 경신도 꿈은 아니지.","JPN":"この調子なら、コースレコードの更新も夢じゃない。","ENG":"At this rate, breaking the course record might just be within reach.","TWN":"照這個氣勢下去，要更新最快圈速也不是夢。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SENIOR_NPC_NULL_NULL","text":{"KOREA":"그건 무리일 겁니다. 두 번째라면 뭐...... 가능성이 있지만요.","JPN":"それは無理だと思います。でも2位なら、まあ……","ENG":"I doubt it. Maybe second place, sure... That's feasible enough.","TWN":"那不可能吧。不過第二名……那倒是還有可能。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DIRECTOR_NPC_NULL_NULL","text":{"KOREA":"하긴 그건 그렇지.","JPN":"それはそうだな。","ENG":"I suppose you're right.","TWN":"也是。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DRIVER_NPC_NULL_NULL","text":{"KOREA":"코스레코드...... 그러고 보니 저번에 보여주신 그 기록은 대체 뭔가요?","JPN":"コースレコード……そういえば、この前見せてくださった記録は、一体何ですか？","ENG":"Course record... Speaking of which, what was that other record you showed me last time?","TWN":"最快圈速……話說上次看到的那個記錄到底是什麼？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SENIOR_NPC_NULL_NULL","text":{"KOREA":"뭐긴? 그야, 말 그대로 이 서킷에서 세워진 최고기록이지.","JPN":"もちろん、そのサーキットでの最高記録だ。","ENG":"What else would it be? It's the highest record from this circuit.","TWN":"還能是什麼？就是字面意思，在這個賽車場上創下的最高紀錄啊。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DRIVER_NPC_NULL_NULL","text":{"KOREA":"하지만 제가 알고 있는 바로는 우승자들 중에서도 그런 기록을 세운 사람은 없었는데요.","JPN":"しかし、俺が知る限りでは優勝者の中にも、これほどの記録を残した人はいません。","ENG":"But as far as I know, not even any of the champions have a record like that.","TWN":"但就我所知，獲勝者中沒有人創下過這樣的記錄啊。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DIRECTOR_NPC_NULL_NULL","text":{"KOREA":"그야 타임 트라이얼에서 세운 비공식 기록이니까.","JPN":"そりゃあ、タイムトライアルでの非公式記録だからだ。","ENG":"That's because it was an unofficial record broken during the time trial.","TWN":"因為那是在計時賽創下的非官方記錄。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DIRECTOR_NPC_NULL_NULL","text":{"KOREA":"꽤 예전 일이라서 자넨 누군지도 모를 걸?","JPN":"かなり前のことだから、お前は知らないはずだ。","ENG":"It was from quite a while ago, so you probably don't even know who that was.","TWN":"很久以前的事情了，你應該都不知道那是誰吧。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DRIVER_NPC_NULL_NULL","text":{"KOREA":"제가 모르는 사람이라고요? 그 엄청난 기록이?","JPN":"あんなすごい記録を残してるのに、俺が知らないなんて……","ENG":"It's someone I don't know? Whoever broke that incredible record?","TWN":"一個我不知道的人？創下了那個驚人的記錄？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DIRECTOR_NPC_NULL_NULL","text":{"KOREA":"굉장히 젊은 선수였는데, 이미 한참 전에 은퇴했거든.","JPN":"すごく若い選手だったが、ずいぶん前に引退したんだ。","ENG":"It was a very young driver, but she retired a long time ago.","TWN":"她是一位非常年輕的選手，但很久前就已經退役了。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DRIVER_NPC_NULL_NULL","text":{"KOREA":"이런...... 복귀가 어려울 정도로 큰 사고였나요?","JPN":"ああ……復帰できないほどの事故だったんですか？","ENG":"Oh dear... Did she get into an accident so bad that she couldn't drive again?","TWN":"怎麼會……是發生了什麼嚴重的事故，受了重傷嗎？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SENIOR_NPC_NULL_NULL","text":{"KOREA":"아니? 멀쩡하게 제 발로 뛰쳐나갔다.","JPN":"いや？　何事もなかったぞ？","ENG":"Uh, not actually. She walked away on her own two feet.","TWN":"沒有啦，她是用自己健全的雙腿跑掉的。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};